import { createFileRoute } from "@tanstack/react-router";
import { useState, useCallback, useEffect } from "react";

// @ts-expect-error - Route tree auto-generated by TanStack Router; regenerated on dev start
export const Route = createFileRoute("/pricing")({
  component: PricingPage,
});

const PLANS = [
  {
    id: "free",
    name: "Free",
    price: "$0",
    period: "forever",
    description: "Get started with AI-powered video editing",
    features: [
      "5 edits per month",
      "720p export resolution",
      "Chat UI only",
      "Basic AI effects",
      "Community support",
    ],
    cta: "Get Started",
    highlighted: false,
    paddlePriceId: null,
  },
  {
    id: "pro",
    name: "Pro",
    price: "$19",
    period: "/mo",
    description: "Full power for professional editors",
    features: [
      "Unlimited edits",
      "4K export resolution",
      "Kove Advanced access",
      "Priority rendering queue",
      "Advanced AI effects",
      "Reference style replication",
      "Priority support",
    ],
    cta: "Start Free Trial",
    highlighted: true,
    paddlePriceId: "pro_monthly_19", // Replace with actual Paddle price ID
  },
];

function PricingPage() {
  const [loading, setLoading] = useState(false);
  const [userTier, setUserTier] = useState<string | null>(null);
  const [paddleLoaded, setPaddleLoaded] = useState(false);

  useEffect(() => {
    // Check current user tier
    fetch("/api/billing/usage")
      .then((r) => r.json())
      .then((data: any) => {
        if (data.tier) setUserTier(data.tier);
      })
      .catch(() => {});
  }, []);

  useEffect(() => {
    // Load Paddle.js script
    const script = document.createElement("script");
    script.src = "https://cdn.paddle.com/paddle/v2/paddle.js";
    script.async = true;
    script.onload = () => {
      const paddleEnv = import.meta.env.VITE_PADDLE_ENV || "sandbox";
      const paddleToken = import.meta.env.VITE_PADDLE_CLIENT_TOKEN;
      if (window.Paddle && paddleToken) {
        window.Paddle.Environment.set(paddleEnv);
        window.Paddle.Setup({ vendor: Number(paddleToken) });
        setPaddleLoaded(true);
      }
    };
    document.head.appendChild(script);

    return () => {
      document.head.removeChild(script);
    };
  }, []);

  const handleCheckout = useCallback(
    async (priceId: string | null) => {
      if (!priceId) return;
      setLoading(true);

      try {
        const resp = await fetch("/api/billing/checkout", {
          method: "POST",
          headers: { "Content-Type": "application/json" },
          body: JSON.stringify({ priceId }),
        });

        const data = (await resp.json()) as {
          success: boolean;
          transactionId?: string;
          error?: string;
        };

        if (!data.success) {
          alert(data.error || "Failed to create checkout session");
          setLoading(false);
          return;
        }

        // Open Paddle overlay checkout
        if (window.Paddle && data.transactionId) {
          window.Paddle.Checkout.open({
            transactionId: data.transactionId,
          });
        } else {
          alert("Paddle checkout not available. Please try again.");
        }
      } catch (err) {
        console.error("Checkout error:", err);
        alert("An error occurred. Please try again.");
      } finally {
        setLoading(false);
      }
    },
    [],
  );

  return (
    <div className="min-h-screen bg-[#0a0a0a] text-white">
      {/* Header */}
      <div className="max-w-4xl mx-auto px-6 pt-16 pb-8 text-center">
        <h1 className="text-4xl font-bold mb-4">Simple, transparent pricing</h1>
        <p className="text-zinc-400 text-lg">
          Start free. Upgrade when you need more power.
        </p>
      </div>

      {/* Plans */}
      <div className="max-w-4xl mx-auto px-6 pb-24">
        <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
          {PLANS.map((plan) => (
            <div
              key={plan.id}
              className={`relative rounded-2xl p-8 ${
                plan.highlighted
                  ? "bg-gradient-to-b from-orange-500/10 to-transparent border border-orange-500/30"
                  : "bg-zinc-900/50 border border-zinc-800"
              }`}
            >
              {plan.highlighted && (
                <div className="absolute -top-3 left-1/2 -translate-x-1/2 px-3 py-1 bg-orange-500 text-white text-xs font-semibold rounded-full">
                  Most Popular
                </div>
              )}

              <h2 className="text-xl font-semibold mb-2">{plan.name}</h2>
              <div className="flex items-baseline gap-1 mb-4">
                <span className="text-4xl font-bold">{plan.price}</span>
                <span className="text-zinc-500">{plan.period}</span>
              </div>
              <p className="text-zinc-400 text-sm mb-6">{plan.description}</p>

              <button
                onClick={() => handleCheckout(plan.paddlePriceId)}
                disabled={loading || (userTier === "pro" && plan.id === "free") || (userTier === "free" && plan.id === "free")}
                className={`w-full py-3 px-4 rounded-lg font-medium text-sm transition-all ${
                  plan.highlighted
                    ? "bg-orange-500 hover:bg-orange-600 text-white"
                    : "bg-zinc-800 hover:bg-zinc-700 text-zinc-200"
                } ${
                  (loading || userTier === plan.id)
                    ? "opacity-50 cursor-not-allowed"
                    : "cursor-pointer"
                }`}
              >
                {userTier === plan.id
                  ? "Current Plan"
                  : userTier === "pro" && plan.id === "free"
                    ? "Downgrade"
                    : plan.cta}
              </button>

              <ul className="mt-8 space-y-3">
                {plan.features.map((feature) => (
                  <li key={feature} className="flex items-center gap-3 text-sm text-zinc-300">
                    <svg
                      className={`w-4 h-4 flex-shrink-0 ${
                        plan.highlighted ? "text-orange-400" : "text-zinc-500"
                      }`}
                      fill="none"
                      viewBox="0 0 24 24"
                      stroke="currentColor"
                      strokeWidth={2}
                    >
                      <path
                        strokeLinecap="round"
                        strokeLinejoin="round"
                        d="M5 13l4 4L19 7"
                      />
                    </svg>
                    {feature}
                  </li>
                ))}
              </ul>
            </div>
          ))}
        </div>

        {/* FAQ */}
        <div className="mt-16 max-w-2xl mx-auto">
          <h2 className="text-2xl font-semibold text-center mb-8">Frequently asked questions</h2>
          <div className="space-y-6">
            {[
              {
                q: "What counts as an edit?",
                a: "Each time you generate or refine an EDL counts as one edit. Previewing and browsing don't count.",
              },
              {
                q: "Can I switch between plans?",
                a: "Yes. Upgrade anytime and your new features activate immediately. Downgrade takes effect at the end of your billing period.",
              },
              {
                q: "Do you handle taxes?",
                a: "Yes. Paddle is our Merchant of Record — they handle all taxes, compliance, and payment processing globally.",
              },
              {
                q: "Is there a free trial for Pro?",
                a: "Your first month on Pro is a full-featured trial. Cancel anytime before the period ends and you won't be charged.",
              },
            ].map((faq) => (
              <div key={faq.q}>
                <h3 className="font-medium mb-1">{faq.q}</h3>
                <p className="text-sm text-zinc-400">{faq.a}</p>
              </div>
            ))}
          </div>
        </div>
      </div>
    </div>
  );
}

// Extend Window for Paddle.js global
declare global {
  interface Window {
    Paddle?: {
      Environment: { set: (env: string) => void };
      Setup: (config: { vendor: number }) => void;
      Checkout: { open: (config: { transactionId: string }) => void };
    };
  }
}
